class Solution:
    def numSubmatrixSumTarget(self, matrix, target):
        m = len(matrix)
        n = len(matrix[0])
        pre = [[0] * (n + 1) for _ in range(m + 1)]
        for i in range(m):
            for j in range(n):
                pre[i + 1][j + 1] = matrix[i][j] + pre[i][j + 1] + pre[i + 1][j] - pre[i][j]
        count = 0
        for x1 in range(1, m + 1):
            for x2 in range(x1, m + 1):
                for y1 in range(1, n + 1):
                    for y2 in range(y1, n + 1):
                        s = pre[x2][y2] - pre[x1 - 1][y2] - pre[x2][y1 - 1] + pre[x1 - 1][y1 - 1]
                        if s == target:
                            count += 1
        return count

