class Solution:
    def numSubmatrixSumTarget(self, matrix, target):
        m = len(matrix)
        n = len(matrix[0])
        count = 0
        for top in range(m):
            col = [0] * n
            for bottom in range(top, m):
                for j in range(n):
                    col[j] += matrix[bottom][j]
                seen = {0: 1}
                running = 0
                for v in col:
                    running += v
                    count += seen.get(running - target, 0)
                    seen[running] = seen.get(running, 0) + 1
        return count

